using ModelContextProtocol.Server;
using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json.Serialization;

[McpServerToolType]
public static class ApiTools
{
    [McpServerTool, Description("Get a list of todos for a given user.")]
    public static async Task<string> GetUserTodos(
        IHttpClientFactory httpClientFactory,
        [Description("The numeric user ID to look up.")] int userId)
    {
        using var client = httpClientFactory.CreateClient("api");
        var todos = await client.GetFromJsonAsync<List<Todo>>(
            $"/todos?userId={userId}");

        if (todos is null || todos.Count == 0)
            return "No todos found for that user.";

        return string.Join("\n", todos.Select(t =>
            $"[{(t.Completed ? "x" : " ")}] {t.Title}"));
    }

    [McpServerTool, Description("Get a specific post by its ID.")]
    public static async Task<string> GetPost(
        IHttpClientFactory httpClientFactory,
        [Description("The numeric post ID.")] int postId)
    {
        using var client = httpClientFactory.CreateClient("api");
        var post = await client.GetFromJsonAsync<Post>($"/posts/{postId}");

        return post is null
            ? "Post not found."
            : $"## {post.Title}\n\n{post.Body}";
    }
}

public record Todo(
    [property: JsonPropertyName("userId")] int UserId,
    [property: JsonPropertyName("id")] int Id,
    [property: JsonPropertyName("title")] string Title,
    [property: JsonPropertyName("completed")] bool Completed);

public record Post(
    [property: JsonPropertyName("userId")] int UserId,
    [property: JsonPropertyName("id")] int Id,
    [property: JsonPropertyName("title")] string Title,
    [property: JsonPropertyName("body")] string Body);

